insert into job_postings (company_id, source, dedupe_hash, title, description, url, is_remote, current_score, current_verdict, remote_signal, lead_state) values ((select id from companies where normalized_name = 'ovadiahearthealth'), 'indeed', 'fa10f1178367', 'Patient Care Coordinator', '**About the Role** We''re looking for a highly organized, proactive **Patient Care Coordinator** to become the operational backbone of our growing virtual practice. In this role, you''ll ensure every patient receives an exceptional experience by coordinating the behind\-the\-scenes details that keep care moving seamlessly. From ordering labs and securing prior authorizations to scheduling appointments and supporting our clinical team, you''ll play a vital role in ensuring nothing falls through the cracks. You''ll work closely with our Practice Manager and collaborate with a small, high\-performing', 'https://www.indeed.com/viewjob?jk=588d92977de3f8fb', true, 100, 'qualified', 'explicit-remote', 'qualified') on conflict (dedupe_hash) do nothing;
insert into job_postings (company_id, source, dedupe_hash, title, description, url, is_remote, current_score, current_verdict, remote_signal, lead_state) values ((select id from companies where normalized_name = 'advancedbillingconsultants'), 'indeed', '5fe3838bc0d2', 'EPIC Software Cardiology Insurance Claims Specialist', 'Company Overview Advanced Billing Consultants is a privately owned California\-based medical billing service provider dedicated to supporting physicians across the region. Our passion is your success! We empower medical practices to achieve consistent and reliable revenue, enabling growth through expanded locations and additional practitioners. With longstanding industry relationships, we are experts in navigating insurance processes and coding standards. Job Overview We are seeking an energetic and detail\-oriented EPIC Software Cardiology Insurance Claims Specialist to join our dynamic team.', 'https://www.indeed.com/viewjob?jk=7751e241b9f8faf9', true, 100, 'qualified', 'explicit-remote', 'qualified') on conflict (dedupe_hash) do nothing;
insert into job_postings (company_id, source, dedupe_hash, title, description, url, is_remote, current_score, current_verdict, remote_signal, lead_state) values ((select id from companies where normalized_name = 'medbill'), 'indeed', 'e953d7cc0c8d', 'DME Intake Specialist', '**Medbill: The Preferred DME Billing Resource! Join our team today!!** Medbill is a Durable Medical Equipment (DME) billing company. We work diligently on DME billing issues for our clients. We are looking for full\-time **Intake Specialists** to do the same. Most of our employees work from homes all across the United States. Would you love to have the opportunity to work inches from your kitchen? If you have a great work ethic, can be successful, accountable, and proactive in the comfort of your own residence read on to see if Medbill is for you! At Medbill, we expect results and in return yo', 'https://www.indeed.com/viewjob?jk=7f36c7fe703f0d0b', true, 95, 'qualified', 'explicit-remote', 'qualified') on conflict (dedupe_hash) do nothing;
