insert into job_postings (company_id, source, dedupe_hash, title, description, url, is_remote, current_score, current_verdict, remote_signal, lead_state) values ((select id from companies where normalized_name = 'betterhelp'), 'jobicy', 'e137ddde40d2', 'International SEO/AEO Manager', 'Who are we and why should you join us? BetterHelp is on a mission to remove the traditional barriers to therapy and make mental health care more accessible to everyone. Founded in 2013, we are now the world’s largest online therapy service, providing affordable and convenient therapy across the globe. Our network of over 30,000 licensed therapists has helped millions of people take ownership of their mental health and change their lives forever. And we’re not stopping there – as the unmet need for mental health services continues to grow, BetterHelp is committed to being part of the solution. ', 'https://jobicy.com/jobs/145731-international-seo-aeo-manager', false, 50, 'nurture', 'ambiguous', 'nurture') on conflict (dedupe_hash) do nothing;
